		if(n==0){
			cout<<"NO!"<<endl;
			continue;
		}
		unsigned long long a=n*2+1;
		while(a%2==1){
			a=a*((a+1)/2);
			sum++;
		}
		cout<<sum<<endl;
		sum=0;
	}
